/* tb-hal x86_64 linker script - PVH ELF image, loaded at 1 MiB.
 *
 * Boot contract (verified): the image is an ELF that QEMU (-kernel) and
 * Firecracker boot via the Xen "x86/HVM direct boot ABI" (PVH). Selection is
 * driven SOLELY by the XEN_ELFNOTE_PHYS32_ENTRY note (type 18, name "Xen"),
 * which MUST live in a PT_NOTE program header.
 *   Sources: https://xenbits.xen.org/docs/unstable/misc/pvh.html
 *            xen/include/public/elfnote.h  ("notes ... live in a PT_NOTE
 *            segment and have \"Xen\" in the name field"; PHYS32_ENTRY == 18)
 *
 * Load address = 1 MiB (0x0010_0000) == Firecracker HIMEM_START. ET_EXEC,
 * vaddr == paddr (no AT()), so the PVH loader copies each PT_LOAD to p_paddr
 * and the 32-bit entry runs identity-addressed with paging off.
 */

ENTRY(_start)
OUTPUT_FORMAT(elf64-x86-64)
OUTPUT_ARCH(i386:x86-64)

PHDRS
{
    note PT_NOTE FLAGS(4);          /* R   : the Xen PHYS32_ENTRY note        */
    text PT_LOAD FLAGS(5);          /* R E : .note.Xen, .text, .rodata        */
    data PT_LOAD FLAGS(6);          /* R W : .data, .bss (page tables, stack) */
}

SECTIONS
{
    . = 1M;                          /* 0x0010_0000 */
    __image_start = .;

    /* The note is file-backed (in the text PT_LOAD) AND exposed via PT_NOTE.
     * KEEP() protects it from --gc-sections. 4-byte aligned: some loaders
     * (QEMU) mis-calculate note padding when alignment != 4. */
    .note.Xen : ALIGN(4) {
        KEEP(*(.note.Xen))
    } :text :note

    .text : ALIGN(16) {
        *(.text._start)
        *(.text .text.*)
    } :text

    .rodata : ALIGN(16) {
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
    } :text

    . = ALIGN(4096);
    .data : ALIGN(16) {
        *(.data .data.*)
        *(.sdata .sdata.*)
        *(.got) *(.got.plt)
    } :data

    /* NOBITS. The boot page tables (CR3 root) and the boot stack are placed
     * FIRST, OUTSIDE the [__bss_start, __bss_end) window, so the _start
     * .bss-clear can never zero the page tables we are actively running on.
     * Guest RAM is zero at VM start, and _start additionally zeroes the
     * three table pages before use. */
    .bss (NOLOAD) : ALIGN(4096) {
        *(.boot.pagetables)
        *(.boot.stack)
        __bss_start = .;
        *(.bss .bss.*)
        *(.sbss .sbss.*)
        *(COMMON)
        __bss_end = .;
    } :data

    . = ALIGN(4096);
    __image_end = .;

    /DISCARD/ : {
        *(.eh_frame) *(.eh_frame_hdr)
        *(.note.gnu.*) *(.comment)
        *(.dynamic) *(.dynsym) *(.dynstr) *(.hash) *(.gnu.hash)
        *(.interp) *(.rela .rela.*)
    }
}

//! x86_64 architecture backend for `tb-hal`.
//!
//! Exposes the safe primitives that `tb-hal`'s public API
//! (`serial_init`, `serial_write_byte`, `serial_write_str`, `halt`) delegates
//! to via `arch::mod`. ALL x86_64 `unsafe` and assembly is confined to this
//! `arch::x86_64` subtree (KERNEL-FOUNDATION-SPEC §1); every other crate is
//! `#![forbid(unsafe_code)]`.
//!
//! M0 boot path is PVH: `boot` emits the `XEN_ELFNOTE_PHYS32_ENTRY` note and
//! the (bootstrap-only) 32->64 trampoline; `serial` is the 16550 COM1 driver.

// `_start`, the PVH note and the 32->64 trampoline live here. The module is
// pulled into the final link because the linker script's `ENTRY(_start)`
// turns `_start` into a needed symbol, forcing extraction from the rlib.
pub mod boot;
pub mod serial;

pub use serial::{serial_init, serial_write_byte};

/// Halt the calling (single) vCPU forever.
///
/// Masks interrupts and parks the core in a `hlt` loop. Used as the M0
/// Definition-of-Done terminator after the marker is printed, and as the
/// `#[panic_handler]` fallback in the kernel crate. Never returns.
#[inline]
pub fn halt() -> ! {
    loop {
        // (a) PRE: any CPU state. POST: interrupts masked, core parked; the
        //     function never observably returns (the surrounding loop re-arms
        //     `hlt` after any spurious NMI/SMI wake).
        // (b) ABI: no operands; clobbers nothing; nomem/nostack. `hlt` clears
        //     no caller state; `cli` only affects IF.
        // (c) Tested by: scripts/run-x86_64.sh (kernel halts after emitting
        //     "hello from rust_main\n"; the runner times out and scrapes COM1).
        unsafe {
            core::arch::asm!("cli", "hlt", options(nomem, nostack, preserves_flags));
        }
    }
}

//! x86_64 PVH bootstrap: the A0 32->64 trampoline + the A1 `_start` entry.
//!
//! **Bootstrap-only (M0).** Per KERNEL-FOUNDATION-SPEC §2/§3 (unit A0) the
//! 32->64 trampoline is *deleted* once `tb-vmm` / `tb-boot v0` enters directly
//! in 64-bit long mode. This is the ONLY x86_64 boot assembly in TABOS.
//!
//! Boot contract (verified facts — obey exactly):
//!  * PVH "x86/HVM direct boot ABI": QEMU `-kernel` and Firecracker select PVH
//!    via the `XEN_ELFNOTE_PHYS32_ENTRY` ELF note (type **18**, name **"Xen"**,
//!    desc = 32-bit physical entry point). The note must sit in a `PT_NOTE`
//!    phdr (see kernel/linker/x86_64.ld).
//!      - https://xenbits.xen.org/docs/unstable/misc/pvh.html
//!      - xen/include/public/elfnote.h  (`#define XEN_ELFNOTE_PHYS32_ENTRY 18`)
//!      - note byte layout cross-checked vs Google's
//!        cloud-hypervisor/rust-hypervisor-firmware `src/pvh.rs`.
//!  * On entry the vCPU is in **32-bit protected mode, paging OFF**, with
//!    `cr0 = PE|ET` (all other writable bits clear), `cr4 = 0`, flat 4 GiB
//!    cs/ds/es/ss, and **`%ebx` -> `hvm_start_info`** (pvh.html).
//!  * `hvm_start_info` lives below 4 GiB; magic `0x336ec578` ("xEn3").
//!    - xen/include/public/arch-x86/hvm/start_info.h.
//!
//! The kernel image is loaded at 1 MiB (0x0010_0000); serial is legacy 16550
//! COM1 @ I/O port 0x3F8 (see serial.rs).

use core::arch::global_asm;

global_asm!(
r#"
// ===========================================================================
// PVH ELF note: XEN_ELFNOTE_PHYS32_ENTRY (type 18, name "Xen")
// (a) PRE: linked into a PT_NOTE phdr. POST: QEMU/Firecracker read `desc` and
//     enter at `_start` in 32-bit protected mode, paging off, ebx->start_info.
// (b) ABI: pure data; namesz=4 ("Xen\0"), descsz=4 (.long entry), type=18;
//     4-byte aligned (QEMU mis-pads notes when alignment != 4).
// (c) Tested by: scripts/run-x86_64.sh (the whole PVH boot path under QEMU).
// ===========================================================================
.section .note.Xen, "a", @note
.align 4
.long   4                       // n_namesz = sizeof("Xen\0")
.long   4                       // n_descsz = sizeof(.long entry)
.long   18                      // n_type   = XEN_ELFNOTE_PHYS32_ENTRY
.asciz  "Xen"                    // n_name   (4 bytes incl NUL; already aligned)
.long   _start                  // n_desc   = 32-bit physical entry point

// ---------------------------------------------------------------------------
// Boot GDT: flat, with a 64-bit code segment, used for the far return into
// long mode. The PVH ABI states the OS sets up its own GDT.
// ---------------------------------------------------------------------------
.section .rodata
.align 8
__boot_gdt64:
    .quad 0x0000000000000000    // 0x00 null
    .quad 0x00209A0000000000    // 0x08 64-bit code (L=1,P=1,DPL=0,exec/read)
    .quad 0x0000920000000000    // 0x10 data        (P=1,DPL=0,read/write)
__boot_gdt64_end:
.align 8
__boot_gdt64_ptr:
    .short __boot_gdt64_end - __boot_gdt64 - 1
    .long  __boot_gdt64         // 32-bit base: read by the 32-bit `lgdt`

// ---------------------------------------------------------------------------
// Boot scratch (NOBITS). Placed by the linker BEFORE __bss_start so the
// .bss-clear never wipes the live page tables. CR3 needs 4 KiB alignment.
// ---------------------------------------------------------------------------
.section .boot.pagetables, "aw", @nobits
.align 4096
__boot_pml4: .skip 4096
__boot_pdpt: .skip 4096
__boot_pd:   .skip 4096

.section .boot.stack, "aw", @nobits
.align 16
__boot_stack_bottom: .skip 0x10000     // 64 KiB boot stack
__boot_stack_top:

// ===========================================================================
// A1 `_start` (32-bit PVH entry) + A0 32->64 trampoline.
// (a) PRE: 32-bit protected mode, paging OFF, cr0=PE|ET, cr4=0, flat segments,
//     ebx->hvm_start_info. POST: 64-bit long mode, identity map [0,1GiB),
//     .bss zeroed, rsp on boot stack (16-aligned), rdi=hvm_start_info, then
//     `call rust_main` (rust_main is `-> !`).
// (b) ABI: SysV/x86_64. Builds its own GDT/CR3/EFER.LME/CR0.PG; clobbers all
//     GPRs; preserves ebx until it is moved into rdi (arg0) just before the
//     call; aligns rsp to 16 before `call` (callee sees rsp%16==8).
// (c) Tested by: scripts/run-x86_64.sh (asserts "hello from rust_main\n").
// ===========================================================================
.section .text._start, "ax", @progbits
.code32
.global _start
_start:
    cli
    cld
    lea     esp, [__boot_stack_top]     // 32-bit stack for the far return

    // Zero PML4+PDPT+PD (3 * 4096 bytes) so no stale entry is ever "present".
    lea     edi, [__boot_pml4]
    xor     eax, eax
    mov     ecx, 3072                   // (4096*3)/4 dwords
    rep     stosd

    // PML4[0] = &PDPT | PRESENT|WRITE   (high dword stays 0 from the zeroing)
    lea     edi, [__boot_pml4]
    lea     eax, [__boot_pdpt]
    or      eax, 0x3
    mov     [edi], eax

    // PDPT[0] = &PD | PRESENT|WRITE
    lea     edi, [__boot_pdpt]
    lea     eax, [__boot_pd]
    or      eax, 0x3
    mov     [edi], eax

    // PD[i] = (i * 2 MiB) | PRESENT|WRITE|PS  ->  identity-map [0, 1 GiB)
    lea     edi, [__boot_pd]
    mov     eax, 0x83                   // PRESENT|WRITE|PS (2 MiB page)
    mov     ecx, 512
.Lpd_fill:
    mov     [edi], eax                  // low dword = phys | flags
    add     eax, 0x200000               // += 2 MiB
    add     edi, 8                      // next 8-byte PD entry
    dec     ecx
    jnz     .Lpd_fill

    // CR4.PAE (bit 5) - required before enabling long-mode paging.
    mov     eax, cr4
    or      eax, (1 << 5)
    mov     cr4, eax

    // CR3 = PML4 physical base.
    lea     eax, [__boot_pml4]
    mov     cr3, eax

    // EFER.LME (IA32_EFER, MSR 0xC000_0080, bit 8).
    mov     ecx, 0xC0000080
    rdmsr
    or      eax, (1 << 8)
    wrmsr

    // CR0.PG (bit 31); PE|ET are already set by PVH. Paging now on.
    mov     eax, cr0
    or      eax, (1 << 31)
    mov     cr0, eax

    // Load the 64-bit GDT and far-RET into the 64-bit code segment (sel 0x08).
    // Loading a CS with L=1 while EFER.LME=1 & CR0.PG=1 activates 64-bit mode.
    lgdt    [__boot_gdt64_ptr]
    push    0x08                        // CS selector
    lea     eax, [.Llong_mode]
    push    eax                         // 32-bit EIP target (< 4 GiB)
    retf

.code64
.Llong_mode:
    // Reload data/stack selectors against our GDT (sel 0x10).
    mov     ax, 0x10
    mov     ss, ax
    mov     ds, ax
    mov     es, ax
    mov     fs, ax
    mov     gs, ax

    lea     rsp, [rip + __boot_stack_top]

    // Clear .bss : [__bss_start, __bss_end). Excludes the page tables/stack.
    lea     rdi, [rip + __bss_start]
    lea     rcx, [rip + __bss_end]
    sub     rcx, rdi
    xor     eax, eax
    rep     stosb

    // hvm_start_info pointer: was in ebx, becomes SysV arg0 (rdi). It is a
    // sub-4 GiB physical address, so `mov edi, ebx` zero-extends correctly.
    mov     edi, ebx

    and     rsp, -16                    // SysV: 16-byte aligned before `call`
    call    rust_main                   // extern "C" fn rust_main(usize) -> !

    // rust_main is `-> !`; belt-and-suspenders halt if it ever returns.
.Lhalt:
    cli
    hlt
    jmp     .Lhalt
"#
);

//! Legacy 16550 UART driver — COM1 @ I/O port 0x3F8 (the earliest serial out).
//!
//! Polled, interrupt-free TX. Works on QEMU `microvm` (ISA serial, on by
//! default) and on Firecracker (whose serial is a 16550A at 0x3F8 as well).
//! Register offsets and the init sequence follow the National 16550 datasheet
//! as documented on the OSDev wiki "Serial Ports" page; LSR bit 5 (0x20) is
//! THRE — Transmit Holding Register Empty.

/// COM1 base I/O port.
const COM1: u16 = 0x3F8;

// 16550 register offsets from the base port. With LCR.DLAB=1, offset 0/1 become
// the divisor latches DLL/DLM instead of THR/IER.
const THR: u16 = 0; // W: Transmit Holding Reg (DLAB=0) / DLL divisor-low (DLAB=1)
const IER: u16 = 1; // Interrupt Enable Reg    (DLAB=0) / DLM divisor-high (DLAB=1)
const FCR: u16 = 2; // W: FIFO Control Register
const LCR: u16 = 3; // Line Control Register (bit 7 = DLAB)
const MCR: u16 = 4; // Modem Control Register
const LSR: u16 = 5; // Line Status Register (bit 5 = THRE)

const LSR_THRE: u8 = 0x20; // TX holding register empty

/// Write one byte to an x86 I/O port.
///
/// (a) PRE: `port` is a valid 16-bit I/O port. POST: `val` is written to it.
/// (b) ABI: `out dx, al`; reads dx/al, writes nothing; nomem/nostack/
///     preserves_flags (port I/O has a side effect but touches no RAM).
/// (c) Tested by: scripts/run-x86_64.sh (every emitted serial byte).
#[inline]
unsafe fn outb(port: u16, val: u8) {
    unsafe {
        core::arch::asm!(
            "out dx, al",
            in("dx") port,
            in("al") val,
            options(nomem, nostack, preserves_flags),
        );
    }
}

/// Read one byte from an x86 I/O port.
///
/// (a) PRE: `port` is a valid 16-bit I/O port. POST: returns the byte read.
/// (b) ABI: `in al, dx`; reads dx, writes al; nomem/nostack/preserves_flags.
///     NOT `pure`, so the LSR poll loop re-reads on every iteration.
/// (c) Tested by: scripts/run-x86_64.sh (LSR polling in `serial_write_byte`).
#[inline]
unsafe fn inb(port: u16) -> u8 {
    let val: u8;
    unsafe {
        core::arch::asm!(
            "in al, dx",
            out("al") val,
            in("dx") port,
            options(nomem, nostack, preserves_flags),
        );
    }
    val
}

/// Initialise COM1: 115200 baud, 8N1, FIFOs enabled, interrupts disabled.
///
/// Divisor 1 against the 1.8432 MHz UART clock => 115200 baud. Idempotent.
pub fn serial_init() {
    unsafe {
        outb(COM1 + IER, 0x00); // disable all UART interrupts
        outb(COM1 + LCR, 0x80); // DLAB = 1 (expose divisor latches)
        outb(COM1 + THR, 0x01); // DLL: divisor low  = 1  -> 115200 baud
        outb(COM1 + IER, 0x00); // DLM: divisor high = 0
        outb(COM1 + LCR, 0x03); // DLAB = 0; 8 data bits, no parity, 1 stop bit
        outb(COM1 + FCR, 0xC7); // FIFO on, clear RX+TX, 14-byte trigger level
        outb(COM1 + MCR, 0x0B); // DTR | RTS | OUT2
    }
}

/// Write one byte to COM1, blocking until the TX holding register is empty.
pub fn serial_write_byte(b: u8) {
    unsafe {
        while inb(COM1 + LSR) & LSR_THRE == 0 {
            core::hint::spin_loop();
        }
        outb(COM1 + THR, b);
    }
}

/* kernel/linker/aarch64.ld
 *
 * Link script for the M0 "boot bring-up" image on the QEMU `virt` board.
 *
 * Load address: QEMU `virt` DRAM base is 0x4000_0000. We link the image at
 * +512 KiB (0x4008_0000) so the low DRAM window stays free for the FDT/DTB
 * that QEMU stages near RAM base -- its pointer is handed to `_start` in x0.
 * 0x4008_0000 mirrors the classic arm64 Image TEXT_OFFSET and is the
 * conventional load address for `-kernel <ELF>` on `virt`. QEMU loads each
 * PT_LOAD at its p_paddr and jumps to e_entry (= `_start`).
 *
 * (The Firecracker aarch64 microVM uses a different base: DRAM_START
 *  0x8000_0000 + 2 MiB = 0x8020_0000. That is a separate run profile / link
 *  script, landed alongside the FDT-driven UART -- see BUILD.md.)
 *
 * Symbols exported for crates/tb-hal/src/arch/aarch64/boot.rs (`_start`):
 *   __bss_start, __bss_end        -- .bss bounds, zeroed at boot
 *   __boot_stack_top              -- initial SP (16 KiB stack, grows down)
 *   __exception_vectors           -- 2 KiB-aligned VBAR_EL1 table (in .text)
 */

ENTRY(_start)

KERNEL_LMA = 0x40080000;

SECTIONS
{
    . = KERNEL_LMA;

    .text : ALIGN(0x800) {
        KEEP(*(.text._start))      /* boot entry -- must be e_entry           */
        KEEP(*(.text._vectors))    /* VBAR_EL1 table, self-aligned to 2 KiB   */
        *(.text .text.*)
    }

    .rodata : ALIGN(8) {
        *(.rodata .rodata.*)
        *(.data.rel.ro .data.rel.ro.*)
        *(.got .got.plt)           /* empty under relocation-model=static     */
    }

    .data : ALIGN(8) {
        *(.data .data.*)
    }

    . = ALIGN(16);
    __bss_start = .;
    .bss (NOLOAD) : ALIGN(16) {
        *(.bss .bss.*)
        *(COMMON)
        . = ALIGN(16);
        __boot_stack_bottom = .;
        . = . + 0x4000;            /* 16 KiB boot stack                       */
        __boot_stack_top = .;
    }
    . = ALIGN(16);
    __bss_end = .;

    /DISCARD/ : {
        *(.eh_frame .eh_frame_hdr)
        *(.note .note.*)
        *(.comment)
        *(.ARM.attributes)
        *(.ARM.exidx .ARM.exidx.*)
    }
}

//! aarch64 backend for the `tb-hal` foundation crate.
//!
//! One of the two `#[cfg(target_arch)]` arms re-exported by `arch/mod.rs`. It
//! exposes exactly the three primitives the safe `tb-hal` public API
//! (`lib.rs`) delegates to on aarch64: [`serial_init`], [`serial_write_byte`]
//! and [`halt`]. (`serial_write_str` is composed in `lib.rs` from
//! `serial_write_byte`, so it is arch-independent.)
//!
//! Boot contract for the M0 QEMU `virt` first-light path (verified facts,
//! KERNEL-FOUNDATION-SPEC §2): the vCPU enters `_start` at **EL1h, MMU OFF,
//! DAIF masked**, with **x0 = FDT/DTB pointer** (AAPCS64 arg0 already).
//! `boot.rs` owns that entry; `serial.rs` owns the PL011 UART.

mod boot; // _start + EL1 vector table; pure side-effect (`global_asm!`) module.
mod serial; // PL011 @ 0x0900_0000 (QEMU `virt` UART0).

pub use serial::{serial_init, serial_write_byte};

// -- halt() -----------------------------------------------------------------
// (a) PRE : any state; called on the M0 happy path after the marker is flushed
//           and from the kernel #[panic_handler]. POST: never returns -- the
//           vCPU is parked in a low-power wait, re-parking on any wake event.
// (b) ABI : `wfi` clobbers nothing, touches no memory/stack, preserves NZCV.
// (c) TEST: scripts/run-aarch64.sh -- the kernel reaches here after printing
//           "hello from rust_main"; the runner times out and asserts the marker.
/// Halt the current vCPU forever (low-power wait loop).
pub fn halt() -> ! {
    loop {
        // SAFETY: `wfi` is an unprivileged hint with no memory or stack
        // effects; it is always legal at EL1 and merely suspends the core
        // until a wake event, after which we loop and re-park.
        unsafe {
            core::arch::asm!("wfi", options(nomem, nostack, preserves_flags));
        }
    }
}

//! aarch64 boot entry (`_start`) and the minimal EL1 exception vector table.
//!
//! All assembly in TABOS is confined to `tb-hal`; this module is the aarch64
//! half of unit **A1/A2** in KERNEL-FOUNDATION-SPEC §3. It is compiled purely
//! for its `global_asm!` side effects -- nothing here is referenced from Rust;
//! the linker keeps `_start` via `ENTRY(_start)` + `KEEP()` in
//! `kernel/linker/aarch64.ld`.
//!
//! Boot contract (QEMU `virt`, `-kernel <ELF>`; verified -- Firecracker sets
//! the parity state PSTATE = 0x3c5 = EL1h with D/A/I/F masked): the vCPU enters
//! at **EL1h, MMU OFF, DAIF masked, x0 = FDT pointer**. QEMU loads the PT_LOAD
//! segments at their p_paddr and jumps to e_entry (`_start`).

use core::arch::global_asm;

// -- _start -----------------------------------------------------------------
// (a) PRE : EL1h, MMU OFF, DAIF masked, x0 = FDT/DTB pointer (QEMU `virt` boot
//           ABI). POST: SP = top of the 16 KiB boot stack, .bss zeroed,
//           VBAR_EL1 = exception table, control tail-branched to
//           rust_main(x0) with x0 (FDT) preserved as AAPCS64 arg0.
// (b) ABI : clobbers x1, x2 only; x0 preserved end-to-end; no stack used before
//           SP is set; `b` (not `bl`) -- rust_main is `-> !`, never returns.
// (c) TEST: scripts/run-aarch64.sh asserts "hello from rust_main".
global_asm!(
    r#"
    .section .text._start, "ax"
    .globl _start
_start:
    // x0 holds the FDT pointer on entry; it is never touched below, so it
    // survives untouched into rust_main as AAPCS64 argument 0.

    // (1) Establish the boot stack (linker guarantees 16-byte alignment).
    adrp x1, __boot_stack_top
    add  x1, x1, :lo12:__boot_stack_top
    mov  sp, x1

    // (2) Zero .bss [__bss_start, __bss_end) eight bytes at a time. Both bounds
    //     are 16-byte aligned, so the doubleword stores never overrun.
    adrp x1, __bss_start
    add  x1, x1, :lo12:__bss_start
    adrp x2, __bss_end
    add  x2, x2, :lo12:__bss_end
0:  cmp  x1, x2
    b.hs 1f
    str  xzr, [x1], #8
    b    0b
1:

    // (3) Point VBAR_EL1 at our (spin-on-fault) table and synchronize, so the
    //     new vector base is in effect before anything could trap.
    adrp x1, __exception_vectors
    add  x1, x1, :lo12:__exception_vectors
    msr  vbar_el1, x1
    isb

    // (4) Enter safe Rust. x0 still = FDT pointer.
    b    rust_main
"#
);

// -- __exception_vectors ----------------------------------------------------
// (a) PRE : VBAR_EL1 set to this 2 KiB-aligned label. POST: any synchronous
//           exception / IRQ / FIQ / SError from any level lands in its 0x80
//           slot and spins in place (M0 has no trap handling -- that is unit
//           A4 / milestone M1).
// (b) ABI : pure code, 16 x 128-byte slots, no registers/memory touched.
// (c) TEST: scripts/run-aarch64.sh -- installing the table must not perturb the
//           happy path (print + halt); a real fault would visibly hang.
global_asm!(
    r#"
    .section .text._vectors, "ax"
    .balign 0x800
    .globl __exception_vectors
__exception_vectors:
    .rept 16
    .balign 0x80
    b   .
    .endr
"#
);

//! PL011 UART driver for the QEMU `virt` board (UART0).
//!
//! M0 first-light hardcodes the QEMU `virt` PL011 base and a polled,
//! transmit-only path -- just enough to emit the DoD marker. Register offsets
//! are from the ARM PrimeCell UART (PL011) Technical Reference Manual, ARM DDI
//! 0183G, §3 "Programmers Model"; the 0x0900_0000 base and 24 MHz UARTCLK are
//! the QEMU `virt` device-tree values (node `pl011@9000000`, clock `clk24mhz`),
//! confirmable via `qemu-system-aarch64 -M virt -machine dumpdtb`.
//!
//! All MMIO is `volatile`. This module lives inside `tb-hal`, the only crate
//! permitted `unsafe`; the two raw-MMIO helpers encapsulate it so the public
//! `serial_init` / `serial_write_byte` surface is safe.

// QEMU `virt` UART0 base. (Firecracker instead exposes an NS16550A -- see the
// FDT note at the bottom of this file.)
const PL011_BASE: usize = 0x0900_0000;

// Register offsets (bytes) -- ARM DDI 0183G, Table 3-1.
const UARTDR: usize = 0x000; // Data register (write = transmit).
const UARTFR: usize = 0x018; // Flag register.
const UARTIBRD: usize = 0x024; // Integer baud-rate divisor.
const UARTFBRD: usize = 0x028; // Fractional baud-rate divisor.
const UARTLCR_H: usize = 0x02C; // Line control.
const UARTCR: usize = 0x030; // Control.
const UARTIMSC: usize = 0x038; // Interrupt mask set/clear.
const UARTDMACR: usize = 0x048; // DMA control.

// Flag register (UARTFR) bits -- DDI 0183G §3.3.3.
const FR_BUSY: u32 = 1 << 3; // UART busy transmitting.
const FR_TXFF: u32 = 1 << 5; // Transmit FIFO full.

// Line control (UARTLCR_H) bits -- DDI 0183G §3.3.7.
const LCR_H_FEN: u32 = 1 << 4; // Enable FIFOs.
const LCR_H_WLEN_8: u32 = 0b11 << 5; // Word length = 8 data bits.

// Control (UARTCR) bits -- DDI 0183G §3.3.8.
const CR_UARTEN: u32 = 1 << 0; // UART enable.
const CR_TXE: u32 = 1 << 8; // Transmit enable.
const CR_RXE: u32 = 1 << 9; // Receive enable.

const IMSC_MASK_ALL: u32 = 0x7FF; // Mask every UART interrupt source.

#[inline(always)]
fn write_reg(offset: usize, value: u32) {
    // SAFETY: `offset` is one of the fixed PL011 register offsets above, so the
    // computed address is a valid, 4-byte-aligned MMIO location for the QEMU
    // `virt` UART0. Early boot is single-threaded; we are the sole accessor.
    unsafe { core::ptr::write_volatile((PL011_BASE + offset) as *mut u32, value) }
}

#[inline(always)]
fn read_reg(offset: usize) -> u32 {
    // SAFETY: as `write_reg`; status reads are side-effect-free loads.
    unsafe { core::ptr::read_volatile((PL011_BASE + offset) as *const u32) }
}

/// Initialise the PL011 for polled, 8N1 transmission at 115200 baud.
///
/// Programming order follows DDI 0183G §3.3.8 (disable, drain, configure,
/// re-enable). On QEMU the divisors are cosmetic, but we set the correct
/// 115200-from-24 MHz values for real-hardware fidelity.
pub fn serial_init() {
    // 1. Disable the UART before reconfiguring it.
    write_reg(UARTCR, 0);
    // 2. Wait for any character currently in flight to drain.
    while read_reg(UARTFR) & FR_BUSY != 0 {}
    // 3. Mask all interrupts and disable DMA (polled, no IRQs in M0).
    write_reg(UARTIMSC, IMSC_MASK_ALL);
    write_reg(UARTDMACR, 0);
    // 4. Baud = UARTCLK / (16 * baud); 24e6 / (16 * 115200) = 13.0208 ->
    //    IBRD = 13, FBRD = round(0.0208 * 64) = 1.
    write_reg(UARTIBRD, 13);
    write_reg(UARTFBRD, 1);
    // 5. 8 data bits, 1 stop, no parity, FIFOs on. LCR_H must be written after
    //    IBRD/FBRD: writing it latches the divisors.
    write_reg(UARTLCR_H, LCR_H_FEN | LCR_H_WLEN_8);
    // 6. Enable the UART and transmitter (RX enabled too, harmlessly).
    write_reg(UARTCR, CR_UARTEN | CR_TXE | CR_RXE);
}

/// Transmit one byte, blocking until the TX FIFO has room.
///
/// Byte-transparent on purpose: no `\n` -> `\r\n` translation, so the serial
/// stream contains the DoD marker `"hello from rust_main\n"` verbatim. Newline
/// policy belongs to a higher layer, not this HAL primitive.
pub fn serial_write_byte(b: u8) {
    while read_reg(UARTFR) & FR_TXFF != 0 {}
    write_reg(UARTDR, b as u32);
}

