//! `tb-hal` — TABOS Hardware Abstraction Layer (M0 surface).
//!
//! This crate is the single место where `unsafe` and assembly are allowed in
//! TABOS (framekernel rule, KERNEL-FOUNDATION-SPEC.md §1). The raw pokes live in
//! the per-arch submodules under `arch/`; THIS file is a thin, fully-safe facade
//! exposing the four symbols the `kernel` crate is allowed to call:
//!
//!   * [`serial_init`]
//!   * [`serial_write_byte`]
//!   * [`serial_write_str`]
//!   * [`halt`]
//!
//! Nothing else is public. `serial_write_str` is implemented here in safe Rust
//! (it just iterates bytes and calls the arch byte-writer), so the only code
//! that ever touches a port/MMIO register is inside `arch/<arch>/serial.rs`.

#![no_std]
#![deny(missing_docs)]

mod arch;

/// Initialise the early serial console for the current architecture.
///
/// * x86_64: legacy 16550 UART, COM1 @ I/O port `0x3F8`.
/// * aarch64: PL011 UART0 @ MMIO `0x0900_0000` (QEMU `virt` first-light).
///
/// Must be called once before any [`serial_write_byte`] / [`serial_write_str`].
pub fn serial_init() {
    arch::serial_init();
}

/// Write a single byte to the early serial console, blocking until the UART can
/// accept it.
pub fn serial_write_byte(b: u8) {
    arch::serial_write_byte(b);
}

/// Write a string to the early serial console, byte by byte (blocking).
///
/// Pure safe Rust: this is just a loop over [`serial_write_byte`]; it performs
/// no `unsafe` itself.
pub fn serial_write_str(s: &str) {
    for &b in s.as_bytes() {
        arch::serial_write_byte(b);
    }
}

/// Halt the (single) vCPU forever. Never returns.
///
/// * x86_64: masked `cli; hlt` spin.
/// * aarch64: `wfe`/`wfi` spin with interrupts masked.
pub fn halt() -> ! {
    arch::halt()
}

//! Architecture dispatch for `tb-hal`.
//!
//! `lib.rs` calls `arch::serial_init()`, `arch::serial_write_byte(b)` and
//! `arch::halt()`. Those three symbols are re-exported here from whichever
//! per-arch submodule matches the build target. The submodules
//! (`arch/x86_64/{mod,boot,serial}.rs`, `arch/aarch64/{mod,boot,serial}.rs`)
//! contain ALL of the crate's `unsafe` + assembly and are emitted separately;
//! THIS file only wires them up.
//!
//! INTERNAL CONTRACT each `arch/<arch>/mod.rs` must satisfy (see BUILD.md):
//!   * `pub fn serial_init();`
//!   * `pub fn serial_write_byte(b: u8);`
//!   * `pub fn halt() -> !;`
//!   * plus the boot entry (`_start`, via `global_asm!`) and the
//!     XEN_ELFNOTE_PHYS32_ENTRY note (x86_64 only), which the linker keeps.

#[cfg(target_arch = "x86_64")]
pub mod x86_64;
#[cfg(target_arch = "x86_64")]
pub use self::x86_64::{halt, serial_init, serial_write_byte};

#[cfg(target_arch = "aarch64")]
pub mod aarch64;
#[cfg(target_arch = "aarch64")]
pub use self::aarch64::{halt, serial_init, serial_write_byte};

#[cfg(not(any(target_arch = "x86_64", target_arch = "aarch64")))]
compile_error!(
    "tb-hal supports only x86_64 and aarch64 (the two Firecracker-class arches); \
     build with --target targets/x86_64-tabos-none.json or \
     targets/aarch64-tabos-none.json"
);

//! TABOS kernel entry shim (M0).
//!
//! Framekernel rule: the kernel crate is otherwise safe Rust
//! (`#![forbid(unsafe_code)]` on every non-shim module added later). THIS file is
//! the single permitted exception. It contains no `unsafe {}` blocks; the only
//! reason crate-level `forbid(unsafe_code)` is not applied here is that
//! `#[unsafe(no_mangle)]` is itself an *unsafe attribute* (it tells the linker to
//! expose `rust_main` un-mangled for tb-hal's `_start` to `call`/`b` into), and
//! the `unsafe_code` lint flags it. All real unsafe + assembly is confined to
//! tb-hal (KERNEL-FOUNDATION-SPEC.md §1).

#![no_std]
#![no_main]

use core::panic::PanicInfo;

/// Boot entry. tb-hal's per-arch `_start` jumps here after it has set up a
/// stack, zeroed `.bss`, and placed the boot-info pointer in arg0 (SysV `rdi`
/// on x86_64 = `hvm_start_info` phys addr; AAPCS64 `x0` on aarch64 = FDT blob).
#[unsafe(no_mangle)]
pub extern "C" fn rust_main(boot_info: usize) -> ! {
    // M0 ignores boot_info; M1+ will parse hvm_start_info / the FDT.
    let _ = boot_info;
    tb_hal::serial_init();
    tb_hal::serial_write_str("hello from rust_main\n");
    tb_hal::halt()
}

/// Panic handler: best-effort marker over serial, then halt forever.
#[panic_handler]
fn panic(_info: &PanicInfo) -> ! {
    tb_hal::serial_write_str("panic\n");
    tb_hal::halt()
}
